import{_ as a,o as i,c as t,a3 as o}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"XiHan.Framework.Threading","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/threading.md","filePath":"cosmos/framework/packages/threading.md","lastUpdated":1783216089000}'),n={name:"cosmos/framework/packages/threading.md"};function d(s,e,r,l,c,h){return i(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="xihan-framework-threading" tabindex="-1">XiHan.Framework.Threading <a class="header-anchor" href="#xihan-framework-threading" aria-label="Permalink to &quot;XiHan.Framework.Threading&quot;">​</a></h1><blockquote><p>并发控制：取消令牌统一管理与跨异步边界的环境作用域（Ambient Scope）传递。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Threading</code></li><li><strong>模块类</strong>：<code>XiHanThreadingModule</code></li><li><strong>所在层</strong>：基础设施层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.Threading 为框架提供异步执行时的上下文管理基础设施。它统一了 <code>CancellationToken</code> 的获取与临时覆盖，并基于 <code>AsyncLocal</code> 实现&quot;环境数据上下文&quot;与&quot;环境作用域&quot;，让一些隐式状态可以安全地跨 <code>await</code> 边界传递、支持嵌套与自动还原。它是缓存、本地化等模块协同工作的底层支撑。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>需要在调用链深处统一取到&quot;当前&quot;的 <code>CancellationToken</code>，而不层层传参。</li><li>需要临时覆盖当前执行上下文的取消令牌，退出作用域后自动还原。</li><li>需要基于 <code>AsyncLocal</code> 存放跨异步边界的隐式状态，并支持嵌套作用域。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Threading</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanThreadingModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><p>模块在 <code>ConfigureServices</code> 中调用 <code>AddXiHanThreading()</code>，注册 <code>ICancellationTokenProvider</code>（默认 <code>NullCancellationTokenProvider</code>）与开放泛型 <code>IAmbientScopeProvider&lt;&gt;</code>。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>取消令牌提供者</strong>：<code>ICancellationTokenProvider</code> 统一提供当前 <code>CancellationToken</code>，避免层层传参。</li><li><strong>令牌临时覆盖</strong>：<code>CancellationTokenOverride</code> + 提供者的 <code>Use()</code> 方法，在作用域内临时替换令牌，退出后还原。</li><li><strong>环境数据上下文</strong>：<code>AsyncLocalAmbientDataContext</code> 基于 <code>AsyncLocal</code> 提供线程安全的异步本地存储。</li><li><strong>环境作用域</strong>：<code>IAmbientScopeProvider&lt;T&gt;</code> 支持嵌套作用域与值覆盖，用栈式管理隐式状态。</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>ICancellationTokenProvider</code></td><td>取消令牌提供者接口，含 <code>Token</code> 属性与 <code>Use()</code> 覆盖方法</td></tr><tr><td><code>CancellationTokenProviderBase</code></td><td>提供者基类，实现令牌覆盖机制的骨架</td></tr><tr><td><code>NullCancellationTokenProvider</code></td><td>空实现，返回 <code>CancellationToken.None</code> 或覆盖值</td></tr><tr><td><code>CancellationTokenOverride</code></td><td>令牌覆盖值容器，用于临时替换</td></tr><tr><td><code>IAmbientDataContext</code> / <code>AsyncLocalAmbientDataContext</code></td><td>环境数据上下文接口与 <code>AsyncLocal</code> 实现</td></tr><tr><td><code>IAmbientScopeProvider&lt;T&gt;</code></td><td>环境作用域提供者，<code>GetValue()</code> / <code>BeginScope()</code></td></tr><tr><td><code>AmbientDataContextAmbientScopeProvider&lt;T&gt;</code></td><td>基于环境数据上下文的作用域提供者实现</td></tr></tbody></table><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li>内部依赖：仅 <a href="./core">XiHan.Framework.Core</a>，无第三方 NuGet 依赖。</li></ul><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./caching">XiHan.Framework.Caching</a> — 与本包的上下文/取消令牌机制协同。</li><li><a href="./localization">XiHan.Framework.Localization</a> — 依赖本包做线程/作用域协调。</li></ul>`,20)])])}const g=a(n,[["render",d]]);export{p as __pageData,g as default};
